def tally_statuses(statuses):
    # Set comprehension to get the distinct statuses, then a dict comprehension
    # mapping each distinct status to how many times it appears. Counting via a
    # dict comprehension keyed on a set keeps it to a single readable expression.
    distinct = {s for s in statuses}
    return {status: statuses.count(status) for status in distinct}

tests.content:
from solution import tally_statuses


def test_counts_each_status():
    statuses = ["pass", "fail", "pass", "skip", "pass", "fail"]
    assert tally_statuses(statuses) == {"pass": 3, "fail": 2, "skip": 1}


def test_returns_a_dict():
    assert isinstance(tally_statuses(["pass"]), dict)


def test_empty_input_gives_empty_dict():
    # Edge: no results means an empty mapping, not an error.
    assert tally_statuses([]) == {}


def test_single_status():
    assert tally_statuses(["pass", "pass"]) == {"pass": 2}


def test_keys_are_exactly_the_distinct_statuses():
    # Edge: keys are the set of distinct values, no duplicates, nothing extra.
    result = tally_statuses(["a", "b", "a"])
    assert set(result.keys()) == {"a", "b"}


def test_total_count_matches_input_length():
    # Tricky: the counts must sum to the number of inputs — catches solutions
    # that miscount or drop occurrences.
    statuses = ["x", "y", "x", "z", "x", "y"]
    result = tally_statuses(statuses)
    assert sum(result.values()) == len(statuses)

from solution import flatten_passed


def _suite(suite_name, *cases):
    # Helper: build a list of case dicts for one suite.
    return [{"suite": suite_name, "name": name, "passed": passed} for name, passed in cases]


def test_flattens_and_filters_passing():
    suites = [
        _suite("auth", ("login", True), ("logout", False)),
        _suite("cart", ("add", True), ("checkout", True)),
    ]
    assert flatten_passed(suites) == ["auth::login", "cart::add", "cart::checkout"]


def test_returns_a_list():
    assert isinstance(flatten_passed([]), list)


def test_empty_suites_give_empty_list():
    # Edge: no suites at all.
    assert flatten_passed([]) == []


def test_empty_inner_suite_contributes_nothing():
    # Edge: a suite with zero cases must not break the flattening.
    suites = [_suite("a"), _suite("b", ("t", True))]
    assert flatten_passed(suites) == ["b::t"]


def test_all_failing_gives_empty_list():
    suites = [_suite("a", ("x", False), ("y", False))]
    assert flatten_passed(suites) == []


def test_preserves_suite_then_case_order():
    # Tricky: the outer loop varies slowest. Result order is suite-by-suite,
    # case-by-case — not interleaved and not reversed.
    suites = [
        _suite("first", ("a", True), ("b", True)),
        _suite("second", ("c", True)),
    ]
    assert flatten_passed(suites) == ["first::a", "first::b", "second::c"]
